<?php
 namespace WPAICG\Core\Providers\OpenAI\Methods; use WPAICG\Core\Providers\OpenAIProviderStrategy; if (!defined('ABSPATH')) { exit; } function get_api_headers_logic(OpenAIProviderStrategy $strategyInstance, string $api_key, string $operation): array { $headers = [ 'Content-Type' => 'application/json', 'Authorization' => 'Bearer ' . $api_key, ]; if ($operation === 'stream') { $headers['Accept'] = 'text/event-stream'; $headers['Cache-Control'] = 'no-cache'; } if (strpos($operation, 'vector_stores') === 0 || strpos($operation, 'assistants') === 0 || $operation === 'files') { $headers['OpenAI-Beta'] = 'assistants=v2'; } return $headers; }